  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ─── Enums ───────────────────────────────────────────────────────────────────\n\nenum UserRole {\n  ATHLETE\n  AGENT\n  CLUB\n}\n\nenum AccountStatus {\n  PENDING_VERIFICATION\n  ACTIVE\n  SUSPENDED\n}\n\nenum FootPreference {\n  LEFT\n  RIGHT\n  BOTH\n}\n\nenum AthleteLevel {\n  PROFESSIONAL\n  AMATEUR\n  YOUTH\n}\n\nenum AvailabilityStatus {\n  FREE\n  EMPLOYED\n}\n\nenum AgencyStatus {\n  REPRESENTED\n  UNREPRESENTED\n}\n\nenum ContractorType {\n  AGENT\n  CLUB\n}\n\nenum ProposalStatus {\n  PENDING\n  ACCEPTED\n  DECLINED\n  RESCHEDULED\n}\n\n// ─── Base user ────────────────────────────────────────────────────────────────\n\nmodel User {\n  id            String        @id @default(cuid())\n  email         String        @unique\n  password      String\n  role          UserRole\n  status        AccountStatus @default(PENDING_VERIFICATION)\n  emailVerified Boolean       @default(false)\n  phoneVerified Boolean       @default(false)\n  createdAt     DateTime      @default(now())\n  updatedAt     DateTime      @updatedAt\n\n  athlete        Athlete?\n  contractor     Contractor?\n  emailCodes     EmailVerificationCode[]\n  passwordResets PasswordReset[]\n\n  @@map(\"users\")\n}\n\n// ─── Athlete ──────────────────────────────────────────────────────────────────\n\nmodel Athlete {\n  id     String @id @default(cuid())\n  userId String @unique\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  // Required (cadastro inicial)\n  fullName     String\n  cpf          String             @unique\n  birthDate    DateTime\n  naturalidade String\n  phone        String\n  position     String\n  dominantFoot FootPreference\n  height       Float\n  weight       Float\n  level        AthleteLevel\n  availability AvailabilityStatus @default(FREE)\n  agencyStatus AgencyStatus       @default(UNREPRESENTED)\n\n  // Identidade visual / vitrine\n  jerseyNumber Int?\n  avatarUrl    String?\n\n  // Pretensão salarial (visível só para clubes)\n  expectedSalary Decimal? @db.Decimal(10, 2)\n\n  // Localização (dados pessoais)\n  city  String?\n  state String?\n\n  // Redes e informações adicionais\n  socialMedia    String?\n  additionalInfo String?\n\n  // Campos desnormalizados — espelham o SeasonStats mais recente para listagem rápida\n  lastClub        String?\n  goals           Int?\n  assists         Int?\n  gamesThisSeason Int?\n  minutesPlayed   Int?\n\n  seasonStats       SeasonStats[]\n  videos            AthleteVideo[]\n  profileViews      ProfileView[]\n  proposalsReceived Proposal[]     @relation(\"AthleteProposals\")\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"athletes\")\n}\n\n// ─── Season Stats (Atributos Técnicos por ano) ───────────────────────────────\n\nmodel SeasonStats {\n  id        String  @id @default(cuid())\n  athleteId String\n  athlete   Athlete @relation(fields: [athleteId], references: [id], onDelete: Cascade)\n\n  year          Int\n  goals         Int            @default(0)\n  assists       Int            @default(0)\n  gamesPlayed   Int            @default(0)\n  minutesPlayed Int            @default(0)\n  position      String\n  height        Float\n  weight        Float\n  dominantFoot  FootPreference\n  lastClub      String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([athleteId, year])\n  @@map(\"season_stats\")\n}\n\n// ─── Athlete Videos ───────────────────────────────────────────────────────────\n\nmodel AthleteVideo {\n  id        String  @id @default(cuid())\n  athleteId String\n  athlete   Athlete @relation(fields: [athleteId], references: [id], onDelete: Cascade)\n\n  url       String\n  title     String?\n  year      Int\n  createdAt DateTime @default(now())\n\n  @@map(\"athlete_videos\")\n}\n\n// ─── Contractor (Agent or Club) ───────────────────────────────────────────────\n\nmodel Contractor {\n  id     String @id @default(cuid())\n  userId String @unique\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  type        ContractorType\n  name        String\n  phone       String\n  cpf         String?        @unique\n  cnpj        String?        @unique\n  companyName String?\n\n  socialMedia    String?\n  additionalInfo String?\n  avatarUrl      String?\n\n  profileViewsMade ProfileView[]\n  proposalsSent    Proposal[]    @relation(\"ContractorProposals\")\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"contractors\")\n}\n\n// ─── Profile Views ────────────────────────────────────────────────────────────\n\nmodel ProfileView {\n  id           String     @id @default(cuid())\n  athleteId    String\n  athlete      Athlete    @relation(fields: [athleteId], references: [id], onDelete: Cascade)\n  contractorId String\n  contractor   Contractor @relation(fields: [contractorId], references: [id], onDelete: Cascade)\n  viewedAt     DateTime   @default(now())\n\n  @@index([athleteId, viewedAt])\n  @@index([contractorId])\n  @@map(\"profile_views\")\n}\n\n// ─── Proposals (Convites) ─────────────────────────────────────────────────────\n\nmodel Proposal {\n  id           String     @id @default(cuid())\n  athleteId    String\n  athlete      Athlete    @relation(\"AthleteProposals\", fields: [athleteId], references: [id], onDelete: Cascade)\n  contractorId String\n  contractor   Contractor @relation(\"ContractorProposals\", fields: [contractorId], references: [id], onDelete: Cascade)\n\n  status      ProposalStatus @default(PENDING)\n  message     String?\n  scheduledAt DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([athleteId, status])\n  @@index([contractorId])\n  @@map(\"proposals\")\n}\n\n// ─── Email verification ───────────────────────────────────────────────────────\n\nmodel EmailVerificationCode {\n  id        String   @id @default(cuid())\n  userId    String\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  code      String\n  expiresAt DateTime\n  used      Boolean  @default(false)\n  createdAt DateTime @default(now())\n\n  @@map(\"email_verification_codes\")\n}\n\n// ─── Password reset ───────────────────────────────────────────────────────────\n\nmodel PasswordReset {\n  id        String   @id @default(cuid())\n  userId    String\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  token     String   @unique\n  expiresAt DateTime\n  used      Boolean  @default(false)\n  createdAt DateTime @default(now())\n\n  @@map(\"password_resets\")\n}\n",
